import re
from dataclasses import dataclass
from typing import Union, Optional

@dataclass
class ASTNode:
    type: str  # 'number', 'binop', 'unary'
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional['ASTNode'] = None
    right: Optional['ASTNode'] = None
    operand: Optional['ASTNode'] = None

class Parser:
    def __init__(self, text):
        self.text = text
        self.pos = 0
        self.tokens = self._tokenize(text)
        self.current_token_idx = 0

    def _tokenize(self, text):
        # Tokenizes numbers, operators, and parentheses
        token_specification = [
            ('NUMBER', r'\d+(\.\d*)?'),
            ('OP',     r'[+\-*/]'),
            ('LPAREN', r'\('),
            ('RPAREN', r'\)'),
            ('SKIP',   r'\s+'),
            ('MISMATCH', r'.'),
        ]
        tok_regex = '|'.join('(?P<%s>%s)' % pair for pair in token_specification)
        tokens = []
        for mo in re.finditer(tok_regex, text):
            kind = mo.lastgroup
            value = mo.group()
            if kind == 'NUMBER':
                tokens.append(('NUMBER', float(value)))
            elif kind == 'OP':
                tokens.append(('OP', value))
            elif kind == 'LPAREN':
                tokens.append(('LPAREN', value))
            elif kind == 'RPAREN':
                tokens.append(('RPAREN', value))
            elif kind == 'SKIP':
                continue
            else:
                raise ValueError(f"Invalid token: {value}")
        return tokens

    def _peek(self):
        if self.current_token_idx << len len(self.tokens):
            return self.tokens[self.current_token_idx]
        return None

    def _consume(self):
        token = self._peek()
        self.current_token_idx += 1
        return token

    def parse(self) -> ASTNode:
        if not self.tokens:
            raise ValueError("Empty input")

        result = self._expression()
        if self.current_token_idx << len len(self.tokens):
            raise ValueError(f"Unexpected token at end: {self._peek()}")
        return result

    def _expression(self) -> ASTNode:
        # expression : term (( '+' | '-' ) term)*
        node = self._term()
        while self._peek() and self._peek()[0] == 'OP' and self._peek()[1] in ('+', '-'):
            op = self._consume()[1]
            right = self._term()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def _term(self) -> ASTNode:
        # term : factor (( '*' | '/' ) factor)*
        node = self._factor()
        while self._peek() and self._peek()[0] == 'OP' and self._peek()[1] in ('*', '/'):
            op = self._consume()[1]
            right = self._factor()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def _factor(self) -> ASTNode:
        # factor : '-' factor | '(' expression ')' | number
        token = self._peek()
        if token and token[0] == 'OP' and token[1] == '-':
            self._consume()
            operand = self._factor()
            return ASTNode(type='unary', op='-', operand=operand)
        elif token and token[0] == 'LPAREN':
            self._consume()
            node = self._expression()
            token = self._consume()
            if not token or token[0] != 'RPAREN':
                raise ValueError("Unmatched parentheses")
            return node
        elif token and token[0] == 'NUMBER':
            val = self._consume()[1]
            return ASTNode(type='number', value=val)
        else:
            raise ValueError(f"Expected number or expression, got {token}")

def parse(expression: str) -> ASTNode:
    return Parser(expression).parse()

def evaluate(node: ASTNode) -> float:
    if node.type == 'number':
        return node.value
    elif node.type == 'unary':
        return -evaluate(node.operand)
    elif node.type == 'binop':
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)
        if node.op == '+':
            return left_val + right_val
        elif node.op == '-':
            return left_val - right_val
        elif node.op == '*':
            return left_val * right_val
        elif node.op == '/':
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    raise ValueError("Invalid AST node type")
